(function ($, Drupal, grapesjs) {
  Drupal.editors.grapesjs_editor = {
    editors: {},
    getFieldName(element) {
      return $(element).attr('name').split('[')[0];
    },
    attach(element, format) {
      /* Rebuild body field */
      const fieldName = this.getFieldName(element);
      const gjsContainer = $('<div/>', {
        id: `gjs-container-${fieldName}`,
        class: 'gjs',
        'data-field-name': $(element).attr('name')
      });
      $(element).parent().prepend(gjsContainer);
      $(element).hide();

      gjsContainer.css({
        'height': '600px',
        'border': '1px solid #444'
      });

      const initEditor = () => {
        const activePlugins = [];

        const pluginMap = {
          'grapesjs-preset-newsletter': 'grapesjs-preset-newsletter',
          // 'drupal-storage': 'drupal-storage',
          'drupal-asset': 'drupal-asset',
          'drupal-blocks': 'drupal-blocks',
          // 'drupal-fields': 'drupal-fields'
        };

        Object.keys(pluginMap).forEach(pluginName => {
          const globalName = pluginMap[pluginName];
          let pluginFn = window[globalName];

          if (pluginFn && pluginFn.default) {
            pluginFn = pluginFn.default;
          }

          if (pluginFn) {
            if (!grapesjs.plugins.get(pluginName)) {
              console.log(`Manually registering plugin: ${pluginName}`);
              grapesjs.plugins.add(pluginName, pluginFn);
            }
            activePlugins.push(pluginName);
          } else {
            if (grapesjs.plugins.get(pluginName)) {
              activePlugins.push(pluginName);
            } else {
              console.warn(`Plugin ${pluginName} not found on window or registry.`);
            }
          }
        });

        let drupalConfig = {};

        console.log('DEBUG: Attach called for format:', format);
        console.log('DEBUG: Full drupalSettings:', drupalSettings);

        if (drupalSettings.editor && drupalSettings.editor.formats) {
          console.log('DEBUG: Available formats:', Object.keys(drupalSettings.editor.formats));
          if (drupalSettings.editor.formats[format]) {
            drupalConfig = drupalSettings.editor.formats[format].editorSettings || {};
          } else {
            console.warn(`DEBUG: Format "${format}" not found in drupalSettings.editor.formats`);
          }
        } else {
          console.warn('DEBUG: drupalSettings.editor or formats property missing');
        }

        console.log('DEBUG: Resolved Drupal Settings:', drupalConfig);

        const defaults = {
          container: gjsContainer.get(0),
          components: $(element).val(),
          height: '100%',
          width: 'auto',
          fromElement: false,
          storageManager: { type: 'none' },
          plugins: activePlugins,
          height: '600px',
          width: 'auto',
          pluginsOpts: {
            'grapesjs-preset-newsletter': {
              modalTitleImport: 'Import Template',
            },
            'drupal-storage': { storeHtml: true },
            'drupal-asset': {},
            'drupal-blocks': { blocks: [] },
            'drupal-fields': { fields: [] }
          },
          canvas: {
            styles: [
              'https://cdnjs.cloudflare.com/ajax/libs/grapesjs/0.21.10/css/grapes.min.css'
            ]
          }
        };

        const grapesSettings = $.extend(true, {}, defaults, drupalConfig);

        grapesSettings.container = gjsContainer.get(0);
        grapesSettings.plugins = activePlugins;
        grapesSettings.storageManager = { type: 'none' };


        console.log('Initializing GrapesJS...', grapesjs.plugins.getAll());
        this.editors[fieldName] = grapesjs.init(grapesSettings);

        this.editors[fieldName].on('load', () => {
          const editor = this.editors[fieldName];

          editor.on('change:changesCount', () => {
            let html = '';
            try {
              html = editor.runCommand('gjs-get-inlined-html');
            } catch (e) {
              console.warn('Could not get inlined HTML, falling back to basic HTML', e);
              html = editor.getHtml() + '<style>' + editor.getCss() + '</style>';
            }

            if (!html) {
              html = editor.getHtml() + '<style>' + editor.getCss() + '</style>';
            }

            $(element).val(html);
          });

          $('input', gjsContainer).on('keydown', function (e) {
            if (e.keyCode === 13) e.preventDefault();
          });
        });
      };

      if (!grapesjs.plugins.get('grapesjs-preset-newsletter')) {
        console.warn('Newsletter plugin not found, loading from local path...');
        const script = document.createElement('script');
        script.src = '/modules/custom/grapesjs_editor/libraries/js/plugins/grapesjs-preset-newsletter/grapesjs-preset-newsletter.min.js';
        script.onload = () => {
          console.log('Plugin loaded from local path.');
          setTimeout(initEditor, 100);
        };
        script.onerror = () => {
          console.error('Failed to load newsletter plugin');
          initEditor();
        };
        document.head.appendChild(script);
      } else {
        initEditor();
      }
    },

    detach(element) {
      const fieldName = this.getFieldName(element);
      const gjsContainer = $(`#gjs-container-${fieldName}`);

      $(element).show();
      this.editors[fieldName].destroy();
      gjsContainer.remove();
    },

    onChange() {
    }
  };
})(jQuery, Drupal, grapesjs);
